import { EventBus } from './event-bus'
import { StateStore } from './state-store'
import { PluginRuntime } from './plugin-runtime'
import {
  PlayerEvent,
  type EngineAdapter,
  type EngineAdapterOptions,
  type PlayerControllerInterface,
  type PlayerSource,
  type PlayerState,
  type TanStackPlugin,
} from './types'

export interface PlayerControllerOptions {
  /** The engine adapter factory (e.g., createVideoJsAdapter) */
  adapter: EngineAdapter
  /** Source(s) to load */
  src: PlayerSource | PlayerSource[]
  /** Auto play on load */
  autoPlay?: boolean
  /** Show native controls */
  controls?: boolean
  /** Fluid responsive layout */
  fluid?: boolean
  /** Preload strategy */
  preload?: 'auto' | 'metadata' | 'none'
  /** Available playback rates */
  playbackRates?: number[]
  /** Engine-specific options */
  engineOptions?: Record<string, unknown>
  /** Plugins to register */
  plugins?: TanStackPlugin[]
}

/**
 * The central player controller.
 * Owns the state store, event bus, plugin runtime, and delegates to the engine adapter.
 */
export class PlayerController implements PlayerControllerInterface {
  readonly eventBus: EventBus
  readonly store: StateStore
  private pluginRuntime: PluginRuntime
  private adapter: EngineAdapter
  private destroyed = false

  constructor(private options: PlayerControllerOptions) {
    this.eventBus = new EventBus()
    this.store = new StateStore()
    this.pluginRuntime = new PluginRuntime()
    this.adapter = options.adapter

    // Wire the adapter's event bridge into our event bus + state store
    this.adapter.setEventBridge((event, data) => {
      this.handleAdapterEvent(event, data)
    })
  }

  /**
   * Initialize the player inside a DOM container.
   * Must be called after construction (allows SSR-safe deferred init).
   */
  init(container: HTMLElement): void {
    const adapterOptions: EngineAdapterOptions = {
      src: this.options.src,
      autoPlay: this.options.autoPlay,
      controls: this.options.controls,
      fluid: this.options.fluid,
      preload: this.options.preload,
      playbackRates: this.options.playbackRates,
      engineOptions: this.options.engineOptions,
    }

    this.adapter.init(container, adapterOptions)

    // Register plugins after adapter is initialized
    if (this.options.plugins) {
      for (const plugin of this.options.plugins) {
        this.pluginRuntime.register(plugin, this, this.eventBus, this.store)
      }
    }
  }

  // ─── Playback Controls ─────────────────────────────────────

  play(): void {
    this.adapter.play()
  }

  pause(): void {
    this.adapter.pause()
  }

  seek(seconds: number): void {
    this.adapter.seek(seconds)
    this.eventBus.emit(PlayerEvent.SEEK, { time: seconds })
  }

  setVolume(value: number): void {
    const clamped = Math.max(0, Math.min(1, value))
    this.adapter.setVolume(clamped)
  }

  setMuted(muted: boolean): void {
    this.adapter.setMuted(muted)
  }

  setPlaybackRate(rate: number): void {
    this.adapter.setPlaybackRate(rate)
  }

  requestFullscreen(): void {
    this.adapter.requestFullscreen()
  }

  exitFullscreen(): void {
    this.adapter.exitFullscreen()
  }

  loadSource(src: PlayerSource | PlayerSource[]): void {
    this.adapter.loadSource(src)
  }

  // ─── Getters ───────────────────────────────────────────────

  getCurrentTime(): number {
    return this.adapter.getCurrentTime()
  }

  getDuration(): number {
    return this.adapter.getDuration()
  }

  getVolume(): number {
    return this.adapter.getVolume()
  }

  getPlaybackRate(): number {
    return this.adapter.getPlaybackRate()
  }

  isFullscreen(): boolean {
    return this.adapter.isFullscreen()
  }

  getState(): PlayerState {
    return this.store.getState()
  }

  getPlugin<P extends TanStackPlugin>(name: string): P | undefined {
    return this.pluginRuntime.get<P>(name)
  }

  // ─── Lifecycle ─────────────────────────────────────────────

  destroy(): void {
    if (this.destroyed) return
    this.destroyed = true

    this.pluginRuntime.destroyAll()
    this.adapter.destroy()
    this.eventBus.emit(PlayerEvent.DESTROYED)
    this.eventBus.removeAll()
    this.store.removeAll()
  }

  // ─── Internal ──────────────────────────────────────────────

  private handleAdapterEvent(event: string, data?: unknown): void {
    // Update state store based on the event
    switch (event) {
      case PlayerEvent.READY:
        this.store.setState({ isReady: true })
        break
      case PlayerEvent.PLAY:
        this.store.setState({ isPlaying: true })
        break
      case PlayerEvent.PAUSE:
        this.store.setState({ isPlaying: false })
        break
      case PlayerEvent.TIME_UPDATE: {
        const payload = data as { currentTime: number; duration: number }
        this.store.setState({
          currentTime: payload.currentTime,
          duration: payload.duration,
        })
        break
      }
      case PlayerEvent.LOADED_METADATA: {
        const payload = data as { duration: number }
        this.store.setState({ duration: payload.duration })
        break
      }
      case PlayerEvent.BUFFER: {
        const payload = data as { buffered: number }
        this.store.setState({ buffered: payload.buffered })
        break
      }
      case PlayerEvent.VOLUME_CHANGE: {
        const payload = data as { volume: number; muted: boolean }
        this.store.setState({ volume: payload.volume, isMuted: payload.muted })
        break
      }
      case PlayerEvent.RATE_CHANGE: {
        const payload = data as { rate: number }
        this.store.setState({ playbackRate: payload.rate })
        break
      }
      case PlayerEvent.FULLSCREEN_CHANGE: {
        const payload = data as { isFullscreen: boolean }
        this.store.setState({ isFullscreen: payload.isFullscreen })
        break
      }
      case PlayerEvent.ENDED:
        this.store.setState({ isPlaying: false })
        break
      case PlayerEvent.ERROR: {
        const payload = data as { error: Error }
        this.store.setState({ error: payload.error })
        break
      }
    }

    // Emit through the event bus for plugins & hooks
    this.eventBus.emit(event, data as any)
  }
}
