import type { PlayerState, StateListener, StateStoreInterface } from './types'
import { INITIAL_STATE } from './types'

/**
 * Lightweight reactive state store.
 * Uses an immutable pattern — each setState creates a new object reference.
 * Subscribers are notified on every state change.
 */
export class StateStore implements StateStoreInterface {
  private state: PlayerState
  private listeners = new Set<StateListener>()

  constructor(initialState?: Partial<PlayerState>) {
    this.state = { ...INITIAL_STATE, ...initialState }
  }

  /** Get a snapshot of the current state (immutable) */
  getState(): PlayerState {
    return this.state
  }

  /** Merge partial updates into state and notify subscribers */
  setState(partial: Partial<PlayerState>): void {
    const prev = this.state
    this.state = { ...prev, ...partial }

    // Only notify if an actual value changed
    const changed = (Object.keys(partial) as (keyof PlayerState)[]).some(
      (key) => prev[key] !== this.state[key]
    )

    if (changed) {
      for (const listener of this.listeners) {
        try {
          listener(this.state)
        } catch (err) {
          console.error('[TanStack Player] Error in state listener:', err)
        }
      }
    }
  }

  /** Subscribe to state changes. Returns an unsubscribe function. */
  subscribe(listener: StateListener): () => void {
    this.listeners.add(listener)
    return () => {
      this.listeners.delete(listener)
    }
  }

  /** Remove all subscribers */
  removeAll(): void {
    this.listeners.clear()
  }
}
