// ─── Player State ───────────────────────────────────────────────

/** Reactive player state tracked by the StateStore */
export interface PlayerState {
  isPlaying: boolean
  isReady: boolean
  duration: number
  currentTime: number
  buffered: number
  volume: number
  playbackRate: number
  isFullscreen: boolean
  isMuted: boolean
  error: Error | null
}

/** Default initial state */
export const INITIAL_STATE: PlayerState = {
  isPlaying: false,
  isReady: false,
  duration: 0,
  currentTime: 0,
  buffered: 0,
  volume: 1,
  playbackRate: 1,
  isFullscreen: false,
  isMuted: false,
  error: null,
}

// ─── Events ─────────────────────────────────────────────────────

/** Standard player events */
export enum PlayerEvent {
  READY = 'ready',
  PLAY = 'play',
  PAUSE = 'pause',
  PROGRESS = 'progress',
  BUFFER = 'buffer',
  ENDED = 'ended',
  ERROR = 'error',
  SEEK = 'seek',
  VOLUME_CHANGE = 'volumechange',
  RATE_CHANGE = 'ratechange',
  FULLSCREEN_CHANGE = 'fullscreenchange',
  TIME_UPDATE = 'timeupdate',
  LOADED_METADATA = 'loadedmetadata',
  DESTROYED = 'destroyed',
}

/** Map of event names → payload types */
export interface PlayerEventMap {
  [PlayerEvent.READY]: void
  [PlayerEvent.PLAY]: void
  [PlayerEvent.PAUSE]: void
  [PlayerEvent.PROGRESS]: { currentTime: number; duration: number }
  [PlayerEvent.BUFFER]: { buffered: number }
  [PlayerEvent.ENDED]: void
  [PlayerEvent.ERROR]: { error: Error }
  [PlayerEvent.SEEK]: { time: number }
  [PlayerEvent.VOLUME_CHANGE]: { volume: number; muted: boolean }
  [PlayerEvent.RATE_CHANGE]: { rate: number }
  [PlayerEvent.FULLSCREEN_CHANGE]: { isFullscreen: boolean }
  [PlayerEvent.TIME_UPDATE]: { currentTime: number; duration: number }
  [PlayerEvent.LOADED_METADATA]: { duration: number }
  [PlayerEvent.DESTROYED]: void
  // Allow custom string events from plugins
  [key: string]: unknown
}

// ─── Engine Adapter ─────────────────────────────────────────────

/** Source configuration */
export interface PlayerSource {
  src: string
  type?: string
}

/** Options passed to the engine adapter on init */
export interface EngineAdapterOptions {
  src: PlayerSource | PlayerSource[]
  autoPlay?: boolean
  controls?: boolean
  fluid?: boolean
  preload?: 'auto' | 'metadata' | 'none'
  playbackRates?: number[]
  /** Engine-specific options (e.g., Video.js config) */
  engineOptions?: Record<string, unknown>
}

/**
 * Engine adapter interface.
 * Adapters (Video.js, HLS.js, etc.) must implement this.
 */
export interface EngineAdapter {
  /** Initialize the engine inside the given container element */
  init(container: HTMLElement, options: EngineAdapterOptions): void

  play(): void
  pause(): void
  seek(seconds: number): void
  setVolume(value: number): void
  setMuted(muted: boolean): void
  setPlaybackRate(rate: number): void
  requestFullscreen(): void
  exitFullscreen(): void
  loadSource(src: PlayerSource | PlayerSource[]): void
  getCurrentTime(): number
  getDuration(): number
  getVolume(): number
  getPlaybackRate(): number
  isFullscreen(): boolean

  /** Clean up and release all resources */
  destroy(): void

  /**
   * Bind the event bridge callback.
   * The adapter should call this function whenever a relevant engine event fires.
   */
  setEventBridge(bridge: EventBridgeFn): void
}

/** Callback the adapter calls to push events into the core event bus */
export type EventBridgeFn = <E extends string>(
  event: E,
  data?: E extends keyof PlayerEventMap ? PlayerEventMap[E] : unknown
) => void

// ─── Plugin System ──────────────────────────────────────────────

/** Context provided to plugins during setup */
export interface PlayerContext {
  /** Player controller instance */
  controller: PlayerControllerInterface
  /** Event bus for subscribing to / emitting events */
  eventBus: EventBusInterface
  /** Reactive state store */
  store: StateStoreInterface
}

/** Plugin interface — all plugins must satisfy this shape */
export interface TanStackPlugin {
  /** Unique plugin name */
  name: string
  /** Called when the plugin is registered */
  setup(ctx: PlayerContext): void
  /** Called when the player is destroyed */
  destroy?(): void
}

/** Factory function for creating plugins with options */
export type PluginFactory<T = void> = T extends void
  ? () => TanStackPlugin
  : (options?: T) => TanStackPlugin

// ─── Controller Interface ───────────────────────────────────────

export interface PlayerControllerInterface {
  play(): void
  pause(): void
  seek(seconds: number): void
  setVolume(value: number): void
  setMuted(muted: boolean): void
  setPlaybackRate(rate: number): void
  requestFullscreen(): void
  exitFullscreen(): void
  loadSource(src: PlayerSource | PlayerSource[]): void
  getCurrentTime(): number
  getDuration(): number
  getVolume(): number
  getPlaybackRate(): number
  isFullscreen(): boolean
  getState(): PlayerState
  destroy(): void
  /** Get a registered plugin by name */
  getPlugin<P extends TanStackPlugin>(name: string): P | undefined
}

// ─── Event Bus Interface ────────────────────────────────────────

export type EventListener<T = unknown> = (data: T) => void

export interface EventBusInterface {
  on<E extends string>(
    event: E,
    listener: EventListener<E extends keyof PlayerEventMap ? PlayerEventMap[E] : unknown>
  ): () => void
  once<E extends string>(
    event: E,
    listener: EventListener<E extends keyof PlayerEventMap ? PlayerEventMap[E] : unknown>
  ): () => void
  off<E extends string>(
    event: E,
    listener: EventListener<E extends keyof PlayerEventMap ? PlayerEventMap[E] : unknown>
  ): void
  emit<E extends string>(
    event: E,
    data?: E extends keyof PlayerEventMap ? PlayerEventMap[E] : unknown
  ): void
}

// ─── State Store Interface ──────────────────────────────────────

export type StateListener = (state: PlayerState) => void

export interface StateStoreInterface {
  getState(): PlayerState
  setState(partial: Partial<PlayerState>): void
  subscribe(listener: StateListener): () => void
}
