import type { EventBusInterface, EventListener, PlayerEventMap } from './types'

/**
 * Typed event emitter for the player.
 * Supports standard player events + custom plugin events.
 */
export class EventBus implements EventBusInterface {
  private listeners = new Map<string, Set<EventListener<any>>>()

  /**
   * Subscribe to an event. Returns an unsubscribe function.
   */
  on<E extends string>(
    event: E,
    listener: EventListener<E extends keyof PlayerEventMap ? PlayerEventMap[E] : unknown>
  ): () => void {
    if (!this.listeners.has(event)) {
      this.listeners.set(event, new Set())
    }
    this.listeners.get(event)!.add(listener)

    return () => this.off(event, listener)
  }

  /**
   * Subscribe to an event once. Auto-removed after first call.
   */
  once<E extends string>(
    event: E,
    listener: EventListener<E extends keyof PlayerEventMap ? PlayerEventMap[E] : unknown>
  ): () => void {
    const wrapper: EventListener<any> = (data) => {
      this.off(event, wrapper)
      listener(data)
    }
    return this.on(event, wrapper)
  }

  /**
   * Unsubscribe a specific listener from an event.
   */
  off<E extends string>(
    event: E,
    listener: EventListener<E extends keyof PlayerEventMap ? PlayerEventMap[E] : unknown>
  ): void {
    const set = this.listeners.get(event)
    if (set) {
      set.delete(listener)
      if (set.size === 0) {
        this.listeners.delete(event)
      }
    }
  }

  /**
   * Emit an event with optional data payload.
   */
  emit<E extends string>(
    event: E,
    data?: E extends keyof PlayerEventMap ? PlayerEventMap[E] : unknown
  ): void {
    const set = this.listeners.get(event)
    if (set) {
      // Iterate over a copy to allow safe removal during iteration
      for (const listener of [...set]) {
        try {
          listener(data)
        } catch (err) {
          console.error(`[TanStack Player] Error in event listener for "${event}":`, err)
        }
      }
    }
  }

  /**
   * Remove all listeners for all events.
   */
  removeAll(): void {
    this.listeners.clear()
  }
}
