import type { PlayerContext, TanStackPlugin, PlayerControllerInterface, EventBusInterface, StateStoreInterface } from './types'

/**
 * Manages the lifecycle of all registered plugins.
 * Calls setup() with a PlayerContext and destroy() on teardown.
 */
export class PluginRuntime {
  private plugins = new Map<string, TanStackPlugin>()

  /**
   * Register and setup a plugin.
   */
  register(
    plugin: TanStackPlugin,
    controller: PlayerControllerInterface,
    eventBus: EventBusInterface,
    store: StateStoreInterface
  ): void {
    if (this.plugins.has(plugin.name)) {
      console.warn(
        `[TanStack Player] Plugin "${plugin.name}" is already registered. Skipping duplicate.`
      )
      return
    }

    const ctx: PlayerContext = { controller, eventBus, store }
    this.plugins.set(plugin.name, plugin)

    try {
      plugin.setup(ctx)
    } catch (err) {
      console.error(`[TanStack Player] Error setting up plugin "${plugin.name}":`, err)
    }
  }

  /**
   * Get a registered plugin by name.
   */
  get<P extends TanStackPlugin>(name: string): P | undefined {
    return this.plugins.get(name) as P | undefined
  }

  /**
   * Destroy all registered plugins and clear the registry.
   */
  destroyAll(): void {
    for (const [name, plugin] of this.plugins) {
      try {
        plugin.destroy?.()
      } catch (err) {
        console.error(`[TanStack Player] Error destroying plugin "${name}":`, err)
      }
    }
    this.plugins.clear()
  }
}
